-- Fresh DB-driven checklist rebuild for KEPR Inspection App.
-- Run this in Supabase SQL Editor when you want to replace the old checklist
-- template/item tables. It does not delete inspections, reports, photos, users,
-- services, or properties.

begin;

drop table if exists public.inspection_checklist_items cascade;
drop table if exists public.inspection_checklist_templates cascade;

create table public.inspection_checklist_templates (
  template_key text primary key,
  inspection_kind text not null default 'flat' check (inspection_kind in ('flat', 'individual', 'society')),
  name text not null,
  icon_name text not null default 'home_work',
  sort_order integer not null default 0,
  is_default boolean not null default false,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table public.inspection_checklist_items (
  id text primary key,
  template_key text not null references public.inspection_checklist_templates(template_key) on delete cascade,
  sort_order integer not null default 0,
  name text not null,
  category text not null default 'General',
  inspection_type text not null default '',
  description text not null default '',
  how_to text not null default '',
  equipment_needed text not null default '',
  severity text not null default 'medium' check (severity in ('low', 'medium', 'high', 'critical')),
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index inspection_checklist_templates_kind_sort_idx
on public.inspection_checklist_templates(inspection_kind, sort_order);

create index inspection_checklist_items_template_sort_idx
on public.inspection_checklist_items(template_key, sort_order);

create table if not exists public.inspection_app_types (
  inspection_type text primary key,
  display_name text not null,
  code_prefix text not null,
  checklist_kind text not null,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  check (inspection_type in ('flat', 'individual', 'society')),
  check (checklist_kind in ('flat', 'society'))
);

  inspection_type,
  display_name,
  code_prefix,
  checklist_kind,
  is_active
)
values
  ('flat', 'Flat Inspection', 'INF', 'flat', true),
  ('individual', 'Individual Home Inspection', 'INP', 'flat', true),
  ('society', 'Society Inspection', 'INS', 'society', true)
on conflict (inspection_type) do update
set
  display_name = excluded.display_name,
  code_prefix = excluded.code_prefix,
  checklist_kind = excluded.checklist_kind,
  is_active = excluded.is_active,
  updated_at = now();

alter table public.inspection_checklist_templates enable row level security;
alter table public.inspection_checklist_items enable row level security;

create policy "inspection app read checklist templates"
on public.inspection_checklist_templates
for select
to anon, authenticated
using (is_active = true);

create policy "inspection app read checklist items"
on public.inspection_checklist_items
for select
to anon, authenticated
using (is_active = true);

















-- Society inspection checklist generated from Sheet2: Apartment Inspection Checklist.

commit;

notify pgrst, 'reload schema';

select
  inspection_kind,
  count(*) as templates
from public.inspection_checklist_templates
group by inspection_kind
order by inspection_kind;

select count(*) as checklist_items
from public.inspection_checklist_items;
